#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

int n,l,q,f[N][50],fa[N];
vector<int> g[N];

void dfs(int x){
    for(int y:g[x])
        if(y!=fa[x]){
            fa[y]=x;
            dfs(y);
        }
}

int main(){
    scanf("%d%d",&n,&l);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++){
        scanf("%d",&f[i][0]);
        for(int j=1;j<50;j++)
            f[i][j]=1;
    }
    dfs(1);
    scanf("%d",&q);
    while(q--){
        int op,x;
        scanf("%d%d",&op,&x);
        if(op==1){
            int d,w;
            scanf("%d%d",&d,&w);
            for(int p=x;d>=0 && p;p=fa[p],d--)
                f[p][d]=1LL*f[p][d]*w%l;
        }else{
            int ans=1;
            for(int p=x,d=0;d<=40;p=max(fa[p],1),d++)
                if(p!=1)
                    ans=1LL*ans*f[p][d]%l*f[p][d+1]%l;
                else
                    ans=1LL*ans*f[p][d]%l;
            printf("%d\n",ans);
        }
    }
    return 0;
}
